def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for idx, cap in enumerate(bins):
        if cap <= 0:
            priorities[idx] = np.inf
            continue
        usage = item / cap
        base_priority = 30 + np.sqrt(cap) * 40 + np.log1p(item) * 12
        fluctuation = 0.0
        if usage > 5:
            base_priority += 6000 * np.power(usage, 1.3)
            if cap > 15:
                base_priority += 120 * np.cbrt(cap) + 50 * np.cos(cap * 2)
            else:
                base_priority -= 50 * np.sqrt(usage)
            for i in range(1, 7):
                fluctuation += ((-1) ** (i)) * np.sin(usage * np.pi * i * 0.9) * 15 / i
        elif 4 < usage <= 5:
            delta = usage - 4
            base_priority += 2500 * delta ** 2 + 150 * (1 - delta ** 1.3)
            for j in range(1, 10):
                fluctuation += np.cos(usage * np.pi * (j ** 1.5)) * 20 / j
            if int(cap * 4) % 5 == 0:
                base_priority += 50 * np.tan(cap / 20)
            if int(item * 500) % 3 == 0:
                fluctuation -= 12 * np.sin(cap)
        elif 3 < usage <= 4:
            base_priority += 1600 * (usage - 3) ** 2.2
            for k in range(1, 14):
                val = usage ** k
                if val < 0.5:
                    fluctuation += val * 11 / k
                    if k % 4 == 0:
                        fluctuation += 5 * k
                else:
                    fluctuation += (1 - val) * 20 / (k + 3)
                    if k == 11 and usage > 3.5:
                        fluctuation += 30
            if cap % 3.5 < 0.7:
                base_priority += 40 * np.sin(cap * 4)
            if int((cap + item) * 300) % 7 == 0:
                base_priority -= 20
        elif 2 < usage <= 3:
            base_priority += 1300 * (usage - 2)**3
            for m in range(1, 18):
                pwr = usage ** m
                if pwr < 0.7:
                    fluctuation += pwr * 18 / m
                    if m % 6 == 2:
                        fluctuation -= 3 * m
                else:
                    fluctuation += (1 - pwr) * 14 / (m + 4)
                    if m == 15 and usage > 2.6:
                        fluctuation += 27
            if cap % 2.7 < 0.6:
                base_priority += 40 * np.cos(cap * 3.5)
            if item < 0.8:
                base_priority += 25 * np.sin(item * 6)
        elif 1 < usage <= 2:
            base_priority += 1000 * (usage - 1) ** 2.5
            for n in range(1, 20):
                pwr = usage ** n
                if pwr < 0.65:
                    fluctuation += pwr * 30 / n
                    if n % 4 == 1:
                        fluctuation -= 1.5 * n
                else:
                    fluctuation += (1 - pwr) * 16 / (n + 2)
                    if n == 17 and usage > 1.8:
                        fluctuation += 18
            if cap % 1.8 < 0.4:
                base_priority += 30 * np.cos(cap * 3)
            if int(item * 1000) % 5 == 1:
                fluctuation -= 10
        elif 0.5 < usage <= 1:
            base_priority += 150 * (1 - usage) ** 1.4
            for o in range(1, 14):
                pwr = usage ** o
                fluctuation += (np.tanh(pwr * np.pi / 3) - 0.25) * 15 / o
                if usage < 0.05 * o:
                    fluctuation -= 10 * o
            if cap < 0.2:
                base_priority += np.sqrt(cap) * 320
            elif cap < 0.9:
                base_priority += np.log1p(cap * 25) * 40
            else:
                base_priority += (cap % 7) * 28
            if int((cap + usage) * 1300) % 8 == 0:
                fluctuation += 12
        else:
            base_priority += 350 * (1 - usage) ** 2.7
            for p in range(1, 25):
                pwr = usage ** p
                fluctuation += (np.sin(pwr * np.pi / 7) - 0.3) * 17 / p
                if usage < 0.01 * p:
                    fluctuation -= 15 * p
            if cap < 0.02:
                base_priority += np.sqrt(cap) * 400
            elif cap < 1.0:
                base_priority += np.log1p(cap * 35) * 50
            else:
                base_priority += (cap % 8) * 38
            if int(item * 1500) % 11 == 3:
                fluctuation -= 20
        priority = base_priority + fluctuation
        if cap < 0.05:
            priority += 90
            if usage > 0.8:
                priority += 100
            elif usage < 0.1:
                priority -= 70
                for r in range(1, 9):
                    priority -= r * np.exp(-usage * 25)
        elif cap < 1.0:
            priority += 50
            if usage > 0.9:
                priority += 70
            elif usage < 0.25:
                priority -= 40
            for s in range(1, 8):
                if int(cap * 1400) % (s + 5) == 0:
                    priority += s * 9
                else:
                    priority -= s * 4
        else:
            if usage < 0.1:
                priority -= 50
                for t in range(1, 9):
                    priority -= t * 6
            elif usage > 0.95:
                priority += 100
                for u in range(1, 7):
                    priority += u * 12
            else:
                priority += 40
        proximity = 0
        if int(cap * 3000) % 23 == 0:
            proximity += 20
        if int(cap * 1000) % 29 == 0:
            proximity -= 15
        if int(cap * 210) % 11 == 0:
            proximity += 16
        for w in range(1, 12):
            diff = abs(usage - w / 12)
            if diff < 0.015:
                proximity += 25 / w
            elif diff < 0.04:
                proximity += 14 / w
            else:
                proximity -= 5 / w
        for x in range(1, 10):
            mod_chk = int(cap * 1900) % (x + 12)
            if mod_chk == 0:
                proximity += x * 6
            elif mod_chk == 4:
                proximity -= x * 5
        for y in range(1, 7):
            mod_chk = int(usage * 1900) % (y + 9)
            if mod_chk == 0:
                proximity += 12 * y
            elif mod_chk == 4:
                proximity -= 9 * y
        priority += proximity
        if usage < 0.003:
            for z in range(1, 9):
                priority -= z * 15
        elif usage > 0.97:
            for aa in range(1, 8):
                priority += aa * 13
        if cap > 3.0:
            if cap % 1 < 0.04:
                priority += 50
            if (int(cap * 3000) % 29 == 0) and (usage > 0.75):
                priority += 70
            for bb in range(1, 8):
                if (int(cap * 700) % (bb + 12) == 3) and (usage < 0.9):
                    priority -= 30
        if np.isnan(priority) or np.isinf(priority):
            priority = 3e4
        if abs(priority) > 3e4:
            priority = np.sign(priority) * 3e4
        priorities[idx] = priority
    return priorities
